// 1. Define the list of target brands (keywords to look for in the URL)
const targetBrands = [
  "ricoma",
  "juki",
  "wilcom",
  "jack",     // Matches 'jack-sewing', 'jack-f4', etc.
  "melco",
  "janome",
  "meifu",
  "organ",    // Matches 'organ-needles'
  "seiko",
  "singer",
  "eisenkolb",
  "brother",
  "epson"
];

// 2. Filter the input items
const filteredItems = $input.all().filter(item => {
  // Get the URL from the 'loc' field, ensure it's lowercase for matching
  const url = (item.json.loc || "").toLowerCase();

  // 3. Check if ANY of the target brands exist inside this URL
  const hasBrand = targetBrands.some(brand => url.includes(brand));

  return hasBrand;
});

return filteredItems;

// 1. Retrieve the raw text safely
const rawText = $input.first().json.data || '';

// 2. Define the cleaning logic
const cleanText = (text) => {
  if (typeof text !== 'string') return text;

  return text
    // 1. Remove HTML tags
    .replace(/<[^>]*>/g, ' ')

    // 2. Remove Markdown code blocks
    .replace(/```[\s\S]*?```/g, ' ')

    // 3. Remove URLs/Links
    .replace(/https?:\/\/[^\s]+/g, '')

    // --- NEW: Remove Script/System Noise ---

    // 4. Remove CSS Variables (e.g., --color-background, --gradient)
    .replace(/--[\w-]+/g, ' ')

    // 5. Remove Object Chains (e.g., window.dataLayer, Shopify.theme, performance.mark)
    .replace(/\b(window|document|Shopify|dataLayer|console|performance)\.[\w\.]+/g, ' ')

    // 6. Remove JS Keywords & Values (e.g., var, function, true, null, await)
    .replace(/\b(var|let|const|function|return|if|else|try|catch|await|import|export|true|false|null|undefined|void|typeof)\b/g, ' ')

    // 7. Remove File extensions often found in code dumps (e.g., .js, .css, .esm)
    .replace(/\b[\w-]+\.(js|css|esm|json)\b/g, ' ')

    // --- End New Filters ---

    // 8. Remove code syntax characters (brackets, parens, equals, colons, semi-colons)
    .replace(/[\{\}\[\]\(\)=:;]/g, ' ')

    // 9. Remove special characters (Keep only: Alphanumeric, spaces, basic punctuation, currency symbols)
    // Added % and $ to keep pricing/specs valid
    .replace(/[^a-zA-Z0-9\s.,?!'"%$-]/g, ' ')

    // 10. Collapse multiple spaces/newlines into a single space
    .replace(/\s+/g, ' ')
    .trim();
};

// 3. Execute and return
return {
  json: {
    cleaned_text: cleanText(rawText)
  }
};

// 1. GET GEMINI DATA (Technical Specs)
// ------------------------------------
// We try two paths to ensure it works whether you use the HTTP Node OR the AI Chain Node
const inputJson = $input.item.json;
let rawContent =$('Enrich Details Using Gemini').first().json.content.parts[0].text; // Path for HTTP Request Node (Gemini API)

if (!rawContent) {
  // Path for n8n standard AI/LangChain Nodes
  rawContent = inputJson.output?.[0]?.content?.[0]?.text || inputJson.text || "";
}

// Clean the Markdown (Remove ```json ... ```)
const cleanJsonString = rawContent
  .replace(/^```json\s*/i, "")
  .replace(/\s*```$/, "")
  .trim();

let productData = {};
try {
  productData = JSON.parse(cleanJsonString);
} catch (e) {
  // If JSON fails, return raw text to help debug
  return { json: { error: "JSON Parse Failed", raw: rawContent } };
}


// 2. GET MANUAL URL (From "Get best User-Manual1")
// ------------------------------------
// We use $('NodeName').item to grab the data from that specific previous step.
let manualUrl = null;

try {
  // Adjust ".url" below to match the exact field name coming out of your Manual node
  // Common names: 'url', 'link', 'source_url', 'manual_url'
  const manualNodeData = $('Get best User-Manual').item.json;
  manualUrl = manualNodeData.url || manualNodeData.manual_url || manualNodeData.link || null;
} catch (error) {
  console.log("Could not find manual node data. defaulting to null.");
}


// 3. MERGE AND RETURN
// ------------------------------------
// We add the manual URL to the Gemini data
productData.manual_url = manualUrl;

return {
  json: productData
};

